  7→
  8→import type {
  9→  DealData,
 10→  DealListParams,
 11→  DealCreateInput,
 12→  DealUpdateInput,
 13→  DealMoveInput,
 14→  DealStageData,
 15→  ApiListResponse,
 16→  ApiResponse,
