 21→export { ApiClientError } from './shared';
 22→
 23→/**
 24→ * Default base URL for API requests
 25→ */
 26→const DEFAULT_BASE_URL = '/api';
 27→
 28→/**
 29→ * Deal API Client
 30→ *
 31→ * Provides typed methods for Deal CRUD operations.
 32→ */
 33→export class DealApiClient {
 34→  private baseUrl: string;
 35→  private fetchFn: typeof globalThis.fetch;
 36→  private defaultHeaders: Record<string, string>;
 37→
 38→  constructor(config: ApiClientConfig = {}) {
 39→    this.baseUrl = config.baseUrl ?? DEFAULT_BASE_URL;
 40→    this.fetchFn = config.fetch ?? fetch;
 41→    this.defaultHeaders = {
 42→      'Content-Type': 'application/json',
 43→      ...config.headers,
 44→    };
 45→  }
 46→
 47→  /**
 48→   * Build full URL for endpoint
 49→   */
 50→  private url(path: string, params?: Record<string, string | undefined>): string {
 51→    const fullUrl = `${this.baseUrl}${path}`;
 52→
 53→    if (params) {
 54→      const searchParams = new URLSearchParams();
 55→      for (const [key, value] of Object.entries(params)) {
 56→        if (value !== undefined) {
 57→          searchParams.append(key, value);
 58→        }
 59→      }
 60→      const queryString = searchParams.toString();
 61→      if (queryString) {
 62→        return `${fullUrl}?${queryString}`;
 63→      }
 64→    }
 65→
 66→    return fullUrl;
 67→  }
 68→
 69→  /**
 70→   * GET /api/deals
 71→   *
 72→   * List all deals with optional filtering.
 73→   */
 74→  async getDeals(params?: DealListParams): Promise<ApiListResponse<DealData>> {
 75→    const response = await this.fetchFn(
 76→      this.url('/deals', {
 77→        pipelineId: params?.pipelineId,
 78→        stageId: params?.stageId,
 79→        managerId: params?.managerId,
 80→        contactId: params?.contactId,
 81→        status: params?.status,
 82→      }),
 83→      {
 84→        headers: this.defaultHeaders,
 85→      }
 86→    );
 87→
 88→    if (!response.ok) {
 89→      return parseApiError(response);
 90→    }
 91→
 92→    return parseJson<ApiListResponse<DealData>>(response);
 93→  }
 94→
 95→  /**
 96→   * GET /api/deals/[id]
 97→   *
 98→   * Fetch a single deal by ID.
 99→   */
100→  async getDeal(id: string): Promise<ApiResponse<DealData>> {
101→    if (!id) {
102→      throw new ApiClientError(400, 'Validation failed', 'id is required');
103→    }
104→
105→    const response = await this.fetchFn(this.url(`/deals/${id}`), {
106→      headers: this.defaultHeaders,
107→    });
108→
109→    if (!response.ok) {
110→      return parseApiError(response);
111→    }
112→
113→    return parseJson<ApiResponse<DealData>>(response);
114→  }
115→
116→  /**
117→   * POST /api/deals
118→   *
119→   * Create a new deal.
120→   */
121→  async createDeal(data: DealCreateInput): Promise<ApiResponse<DealData>> {
122→    const response = await this.fetchFn(this.url('/deals'), {
123→      method: 'POST',
124→      headers: this.defaultHeaders,
125→      body: JSON.stringify(data),
126→    });
127→
128→    if (!response.ok) {
129→      return parseApiError(response);
130→    }
131→
132→    return parseJson<ApiResponse<DealData>>(response);
133→  }
134→
135→  /**
136→   * PATCH /api/deals/[id]
137→   *
138→   * Update an existing deal.
139→   */
140→  async updateDeal(
141→    id: string,
142→    data: DealUpdateInput
143→  ): Promise<ApiResponse<DealData>> {
144→    if (!id) {
145→      throw new ApiClientError(400, 'Validation failed', 'id is required');
146→    }
147→
148→    const response = await this.fetchFn(this.url(`/deals/${id}`), {
149→      method: 'PATCH',
150→      headers: this.defaultHeaders,
151→      body: JSON.stringify(data),
152→    });
153→
154→    if (!response.ok) {
155→      return parseApiError(response);
156→    }
157→
158→    return parseJson<ApiResponse<DealData>>(response);
159→  }
160→
161→  /**
162→   * DELETE /api/deals/[id]
163→   *
164→   * Soft-delete a deal.
165→   */
166→  async deleteDeal(id: string): Promise<ApiResponse<DealData>> {
167→    if (!id) {
168→      throw new ApiClientError(400, 'Validation failed', 'id is required');
169→    }
170→
171→    const response = await this.fetchFn(this.url(`/deals/${id}`), {
172→      method: 'DELETE',
173→      headers: this.defaultHeaders,
174→    });
175→
176→    if (!response.ok) {
177→      return parseApiError(response);
178→    }
179→
180→    return parseJson<ApiResponse<DealData>>(response);
181→  }
182→
183→  /**
184→   * POST /api/deals/[id]/move
185→   *
186→   * Move deal to a different stage.
187→   */
188→  async moveDeal(id: string, data: DealMoveInput): Promise<ApiResponse<DealData>> {
189→    if (!id) {
190→      throw new ApiClientError(400, 'Validation failed', 'id is required');
191→    }
192→
193→    const response = await this.fetchFn(this.url(`/deals/${id}/move`), {
194→      method: 'POST',
195→      headers: this.defaultHeaders,
196→      body: JSON.stringify(data),
197→    });
198→
199→    if (!response.ok) {
200→      return parseApiError(response);
201→    }
202→
203→    return parseJson<ApiResponse<DealData>>(response);
204→  }
205→}
